async function main() {
  try {
    const res = await wixClient.products.queryProducts().limit(100).find();
    console.log(`Searching through ${res.items.length} products...\n`);

    res.items.forEach(p => {
      const name = p.name.toLowerCase();
      if (name.includes('kopp') || name.includes('mug') || name.includes('cup') || name.includes('fear') || name.includes('faith')) {
        console.log(`Product: "${p.name}" (ID: ${p._id})`);
        console.log(`  Description: "${p.description?.replace(/<[^>]*>/g, '').trim()}"`);
        console.log('');
      }
    });
  } catch (err) {
    console.error(err);
  }
}

main();
